// ─── Event-scope features (computed once) ────────────────────────────────
const closes = ctx.underlying.klines.map((k) => k.close);
const rsi = ctx.helpers.rsi(closes, 14);
const emaFast = ctx.helpers.emaArray(closes, 12).at(-1);
const emaSlow = ctx.helpers.emaArray(closes, 26).at(-1);
const emaTrend = Math.sign(emaFast - emaSlow);           // -1 | 0 | +1

const recentCloses = closes.slice(-4);
const shortMomentum =
  recentCloses.length >= 2
    ? (recentCloses.at(-1) - recentCloses[0]) / recentCloses[0]
    : 0;

// ─── Feature → drift + vol multiplier (clamped) ──────────────────────────
const clip = (x, lo, hi) => Math.max(lo, Math.min(hi, x));

const rsiBias = ((rsi - 50) / 50) * 0.02;
const emaBias = emaTrend * 0.015;
const momBias = clip(shortMomentum * 0.5, -0.015, 0.015);
const driftPct = clip(rsiBias + emaBias + momBias, -0.05, 0.05);
const volMult = 1 + Math.min(0.30, 2 * Math.abs(shortMomentum));

// ─── Synthetic shifted underlying — reused by every market ───────────────
const baseVol =
  ctx.underlying.realizedVol?.["1h"] ??
  ctx.underlying.realizedVol?.["24h"] ??
  null;
const sigmaOverride = baseVol !== null ? baseVol * volMult : undefined;
const shiftedUnderlying = {
  ...ctx.underlying,
  price: ctx.underlying.price * (1 + driftPct),
};

// ─── Per-questionType baseline selector (reads mCtx.underlying) ──────────
// Not a dispatcher helper — explicit because the event is mixed-type.
const bucketYes = (mCtx, opts) => {
  switch (mCtx.market.questionType) {
    case "above":
      return ctx.helpers.bsAbove(mCtx, opts);
    case "below":
      return 1 - ctx.helpers.bsAbove(mCtx, opts);
    case "range":
      return ctx.helpers.bsRange(mCtx, opts);
    case "hit":
      return ctx.helpers.bsOneTouch(mCtx, opts);
    default:
      return null; // signal caller to hold
  }
};

const THRESHOLD = 0.04;

return ctx.markets.map((market) => {
  try {
    // Hard filters
    if (market.closed || market.hoursToExpiry < 0) {
      return {
        question: market.question,
        questionType: market.questionType,
        expiryDate: market.expiryDate,
        hoursToExpiry: market.hoursToExpiry,
        decision: "hold",
        reason: "closed or expired",
        spot: ctx.underlying.price,
        strike: market.strike,
        strike2: market.strike2 ?? null,
      };
    }
    if (
      market.questionType === "unknown" ||
      (market.strike === null && market.questionType !== "directional")
    ) {
      return {
        question: market.question,
        questionType: market.questionType,
        expiryDate: market.expiryDate,
        hoursToExpiry: market.hoursToExpiry,
        decision: "hold",
        reason: "unknown type or missing strike",
        spot: ctx.underlying.price,
        strike: market.strike,
        strike2: market.strike2 ?? null,
      };
    }

    // Build mCtx once — shifted underlying drives BOTH the drift AND vol mult
    const mCtx = {
      market,
      underlying: shiftedUnderlying,
      timing: ctx.timing,
    };
    const bsOpts = sigmaOverride !== undefined ? { sigmaOverride } : {};

    // Price each bucket off the shifted distribution
    let probs;
    if (market.questionType === "firstHit") {
      // Defensive branch: target event has no firstHit, but if one appears
      // we still want a consistent shifted-underlying pricing.
      probs = ctx.helpers.firstHitProbabilities(mCtx, {
        ...bsOpts,
        seed: 42,
      });
    } else if (market.questionType === "directional") {
      // No strike → no BS baseline. Directional markets need microstructure
      // edge, not distribution drift. Hold by default.
      return {
        question: market.question,
        questionType: market.questionType,
        expiryDate: market.expiryDate,
        hoursToExpiry: market.hoursToExpiry,
        decision: "hold",
        reason: "directional: no BS baseline under drift model",
        spot: ctx.underlying.price,
        strike: market.strike,
        strike2: market.strike2 ?? null,
      };
    } else {
      const yes = bucketYes(mCtx, bsOpts);
      if (yes === null) {
        return {
          question: market.question,
          questionType: market.questionType,
          expiryDate: market.expiryDate,
          hoursToExpiry: market.hoursToExpiry,
          decision: "hold",
          reason: `unsupported questionType: ${market.questionType}`,
          spot: ctx.underlying.price,
          strike: market.strike,
          strike2: market.strike2 ?? null,
        };
      }
      probs = ctx.helpers.binaryProbsFromYesProb(mCtx, yes);
    }

    // Edge vs live orderbook — edgeFromProbs is strict on 2-simplex
    const edges = ctx.helpers.edgeFromProbs(probs, mCtx);
    const best = edges[0].edge >= edges[1].edge ? edges[0] : edges[1];

    const reason =
      `drift=${(driftPct * 100).toFixed(2)}% ` +
      `volMult=${volMult.toFixed(2)} ` +
      `edge=${best.edge.toFixed(3)}`;

    const base = {
      question: market.question,
      questionType: market.questionType,
      expiryDate: market.expiryDate,
      hoursToExpiry: market.hoursToExpiry,
      probs,
      spot: ctx.underlying.price,
      strike: market.strike,
      strike2: market.strike2 ?? null,
    };

    if (best.edge < THRESHOLD) {
      return { ...base, decision: "hold", edge: best.edge, reason };
    }

    return {
      ...base,
      decision: "buy",
      side: best.label,
      fairPrice: best.fairPrice,
      marketPrice: best.marketPrice,
      edge: best.edge,
      reason,
    };
  } catch (err) {
    return {
      question: market.question,
      questionType: market.questionType,
      decision: "hold",
      reason: `error: ${String(err && err.message ? err.message : err)}`,
      spot: ctx.underlying.price,
      strike: market.strike,
      strike2: market.strike2 ?? null,
    };
  }
});
